  code: string;
  ok: boolean;
  details?: string;
}

export interface WorkspaceDeployCreateInput {
  workspaceId: string;
  deploymentId: string;
  outputDir: string;
  outputBundle: {
    bytes: Uint8Array;
    sha256: string;
  };
